def ensure_output_tree(cfg: Step7Config) -> None:
    for path in [cfg.root, cfg.main_figure_dir, cfg.supplementary_dir, cfg.source_data_dir, cfg.reports_dir, cfg.code_dir]:
        path.mkdir(parents=True, exist_ok=True)


